var numberOfWays = function(s) {
    const n = s.length;
    let totalOnes = 0;
    for (const ch of s) if (ch === '1') totalOnes++;
    const totalZeros = n - totalOnes;
    let zerosBefore = 0, onesBefore = 0, ways = 0;
    for (const ch of s) {
        if (ch === '0') {
            const onesAfter = totalOnes - onesBefore;
            ways += onesBefore * onesAfter;
            zerosBefore++;
        } else {
            const zerosAfter = totalZeros - zerosBefore;
            ways += zerosBefore * zerosAfter;
            onesBefore++;
        }
    }
    return ways;
};
